//! Goal1 binary: two actors on a single thread ping-pong an empty
//! [`Message`] for a caller-supplied duration in seconds (f64).
//! Prints messages-handled/throughput and a `tprobe2` band-table
//! report of per-dispatch latency (ns by default, ticks with
//! `-t`/`--ticks`).
//!
//! Usage: `goal1 <duration_secs> [-t|--ticks]`

use std::time::Duration;

use actor_x1::runtime::SingleThreadRuntime;
use actor_x1::{Actor, Context, Message};

/// Actor that, on every message received, sends exactly one message
/// back to its configured peer.
struct PingPongActor {
    peer_id: u32,
}

impl Actor for PingPongActor {
    /// Forward a single `Message` to `self.peer_id`. Never blocks.
    fn handle_message(&mut self, ctx: &mut dyn Context, _msg: Message) {
        ctx.send(self.peer_id, Message);
    }
}

/// Parsed command-line arguments.
struct Cli {
    duration_s: f64,
    as_ticks: bool,
}

/// Parse argv. Exits(2) with a usage line on any parse error.
fn parse_cli() -> Cli {
    let mut as_ticks = false;
    let mut duration_s: Option<f64> = None;
    for arg in std::env::args().skip(1) {
        match arg.as_str() {
            "-t" | "--ticks" => as_ticks = true,
            other => {
                if duration_s.is_some() {
                    eprintln!("goal1: unexpected argument: {other}");
                    usage_and_exit();
                }
                match other.parse::<f64>() {
                    Ok(v) if v >= 0.0 && v.is_finite() => duration_s = Some(v),
                    _ => {
                        eprintln!("goal1: duration must be a non-negative finite number: {other}");
                        usage_and_exit();
                    }
                }
            }
        }
    }
    let Some(duration_s) = duration_s else {
        usage_and_exit();
    };
    Cli {
        duration_s,
        as_ticks,
    }
}

/// Print usage to stderr and exit with code 2.
fn usage_and_exit() -> ! {
    eprintln!("usage: goal1 <duration_secs> [-t|--ticks]");
    std::process::exit(2);
}

/// Run two ping-pong actors on one thread for the CLI-supplied
/// duration, then print message count, throughput, and the
/// per-dispatch `tprobe2` band-table report.
fn main() {
    let cli = parse_cli();
    let duration = Duration::from_secs_f64(cli.duration_s);

    let mut rt = SingleThreadRuntime::new("goal1.dispatch");
    let a_id = rt.add_actor(Box::new(PingPongActor { peer_id: 1 }));
    let b_id = rt.add_actor(Box::new(PingPongActor { peer_id: 0 }));
    assert_eq!((a_id, b_id), (0, 1));
    rt.seed(a_id, Message);

    let count = rt.run_for(duration);
    let mmps = count as f64 / cli.duration_s / 1e6;
    println!(
        "goal1: {count} messages in {:.3}s ({mmps:.3} M msg/s)",
        cli.duration_s,
    );
    rt.probe_mut().report(cli.as_ticks);
}

