    fn seed_is_handled_and_queue_drains() {
        let mut rt = SingleThreadRuntime::new("test.drain");
        let id = rt.add_actor(Box::new(Sink));
        rt.seed(id, Message);
        let n = rt.run_for(Duration::from_millis(1));
        assert_eq!(n, 1);
    }

