            name: name.to_string(),
            hist: Histogram::<u64>::new_with_bounds(1, 1_000_000_000_000, 3).unwrap(), // OK: bounds are constant and valid (1 ≤ low < high, sigfigs in [0,5])
            records: Vec::new(),
