    let count_w = rows.iter().map(|r| r.count.len()).max().unwrap_or(0); // OK: rows non-empty (see above)
    let mean_w = rows.iter().map(|r| r.mean.len()).max().unwrap_or(0); // OK: rows non-empty (see above)

