            let idx = BOUNDARY_PCTS[1..]
                .iter()
                .position(|&b| mid_rank < b)
                .unwrap_or(n_bands - 1); // OK: mid_rank in [0,1]; same reasoning as above
            if idx < n_bands - 1 {
                let diff = value as f64 - trim_mean;
