//! Apparatus-overhead calibration for [`TProbe2`]. Measures the
//! hardware floor cost of two back-to-back `rdtsc` reads — the
//! bias contaminating every probe scope's stored `end_tsc -
//! start_tsc` delta — and exposes it as a per-batch correction
//! for [`TProbe2::report`].
//!
//! This is a simpler model than `iiac-perf/src/overhead.rs`,
//! which vendored as inspiration but does a two-point fit to
//! separate per-sample framing from per-inner-iteration loop cost.
//! Here we only model per-scope framing because:
//! - [`TProbe2::end`] captures `end_tsc` *before* `Vec::push`, so
//!   the stored delta contains nothing but the two `rdtsc` reads
//!   and whatever work the caller enclosed. No hidden loop cost
//!   inside the scope apparatus.
//! - Any per-iteration loop overhead in the caller's hot path
//!   (queue pop, deadline check, etc.) is part of what the user
//!   is measuring; subtracting it would be wrong.
//!
//! ### `lfence` bracketing
//!
//! `rdtsc` isn't a serializing instruction, so two back-to-back
//! reads with no work between them can execute out-of-order and
//! measure a delta of 0–1 ticks — far below the true apparatus
//! cost. In the runtime hot path the enclosed work acts as an
//! implicit pipeline barrier, so the framing actually contaminating
//! each stored delta is the fully-serialized cost, not the
//! optimistic OoO floor. Calibration uses `_mm_lfence` before and
//! after each read to force the serialized reading so the measured
//! floor matches what real scopes experience. **The bot thinks**
//! this is close enough to the truth for Stage 1; a two-point fit
//! on real workload would be strictly more correct and may land
//! later if single-point calibration proves unstable.
//!
//! The bot thinks a future two-point extension would be worth it
//! if we ever start measuring apparatus that has its own inner
//! loop (e.g. a timer that averages internally).
//!
//! [`TProbe2`]: crate::perf::TProbe2
//! [`TProbe2::report`]: crate::perf::TProbe2::report
//! [`TProbe2::end`]: crate::perf::TProbe2::end

use std::hint::black_box;
use std::time::{Duration, Instant};

/// Calibration warmup iterations — lets CPU frequency boost ramp
/// before the first real sample.
pub const CAL_WARMUP: u64 = 10_000;

/// Samples taken in the minimum-pass. The reported floor approaches
/// the hardware lower bound as samples grow; 100k takes ~1 ms on a
/// modern x86 and is plenty.
pub const CAL_SAMPLES: u64 = 100_000;

/// Apparatus-overhead model fitted by [`calibrate`]. Callers pass a
/// reference to [`TProbe2::report`] (as `Option<&Overhead>`) to get
/// framing subtracted from each stored per-event value.
///
/// [`TProbe2::report`]: crate::perf::TProbe2::report
#[derive(Debug, Clone, Copy)]
pub struct Overhead {
    /// Minimum observed `end_tsc - start_tsc` for a pair of
    /// back-to-back `rdtsc` reads over [`CAL_SAMPLES`] samples,
    /// in raw ticks. This is the framing cost per probe scope,
    /// regardless of scope `batch`.
    pub framing_ticks: u64,
    /// Wall-clock duration of the full calibration run.
    pub cal_duration: Duration,
}

impl Overhead {
    /// Per-event framing correction at a given `batch`, in ticks:
    /// the framing is paid once per scope and amortized across
    /// `batch` events. Integer division truncates toward zero, so
    /// at `batch > framing_ticks` the correction rounds to zero.
    pub fn per_event_ticks(&self, batch: u64) -> u64 {
        self.framing_ticks / batch.max(1)
    }
}

/// Fenced tick read: `lfence; rdtsc; lfence`. Forces the pipeline
/// to serialize on either side so the reading reflects the true
/// framing cost a real probe scope sees (where enclosed work also
/// serializes the pipeline), not the OoO-reduced floor.
#[cfg(target_arch = "x86_64")]
#[inline(always)]
fn read_ticks_fenced() -> u64 {
    // Safe: `_mm_lfence` and `_rdtsc` are valid on any x86_64 CPU
    // (LFENCE requires SSE2, universal on amd64).
    unsafe {
        core::arch::x86_64::_mm_lfence();
        let t = core::arch::x86_64::_rdtsc();
        core::arch::x86_64::_mm_lfence();
        t
    }
}

/// Measure [`CAL_SAMPLES`] back-to-back fenced `rdtsc` pairs,
/// return the minimum delta. Preceded by [`CAL_WARMUP`] throwaway
/// reads to warm CPU frequency / branch predictor. Blocks for
/// ~5 ms on a modern x86 (fences are expensive).
pub fn calibrate() -> Overhead {
    let cal_start = Instant::now();

    for _ in 0..CAL_WARMUP {
        let a = read_ticks_fenced();
        let b = read_ticks_fenced();
        black_box(b.wrapping_sub(a));
    }

    let mut min_ticks = u64::MAX;
    for _ in 0..CAL_SAMPLES {
        let start = read_ticks_fenced();
        let end = read_ticks_fenced();
        let delta = end.saturating_sub(start);
        if delta < min_ticks {
            min_ticks = delta;
        }
    }

    Overhead {
        framing_ticks: min_ticks,
        cal_duration: cal_start.elapsed(),
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn per_event_ticks_amortizes_framing() {
        let ovh = Overhead {
            framing_ticks: 20,
            cal_duration: Duration::from_millis(1),
        };
        assert_eq!(ovh.per_event_ticks(1), 20);
        assert_eq!(ovh.per_event_ticks(10), 2);
        assert_eq!(ovh.per_event_ticks(100), 0); // truncates
        assert_eq!(ovh.per_event_ticks(0), 20); // batch=0 treated as 1
    }

    #[test]
    fn calibrate_returns_positive_ticks_quickly() {
        let ovh = calibrate();
        // Any modern x86 reads rdtsc in < 100 ticks; allow slack.
        assert!(ovh.framing_ticks > 0);
        assert!(ovh.framing_ticks < 10_000);
        // Calibration should complete well under a second.
        assert!(ovh.cal_duration < Duration::from_secs(1));
    }
}

