1	//! Runtimes that drive [`Actor`]s. The single-thread runtime lives
2	//! here today; the multi-thread runtime arrives in a later step.
3	
4	use std::collections::VecDeque;
5	use std::time::{Duration, Instant};
6	
7	use crate::perf::TProbe2;
8	use crate::{Actor, Context, Message};
9	
10	/// Single-threaded runtime: all actors run on the calling thread,
11	/// sharing one FIFO message queue. Dispatch loops until either the
12	/// caller-supplied deadline expires or the queue drains.
13	///
14	/// Dispatch is wrapped in a [`TProbe2`] batched scope covering
15	/// `inner` consecutive `handle_message` calls; per-event latency
16	/// is available via [`Self::probe_mut`] after [`Self::run_for`]
17	/// returns. The scope's `site_id` is the first `dst_id` in the
18	/// batch (arbitrary-but-stable when `inner > 1`).
19	pub struct SingleThreadRuntime {
20	    actors: Vec<Box<dyn Actor>>,
21	    queue: VecDeque<(u32, Message)>,
22	    probe: TProbe2,
23	}
24	
25	impl SingleThreadRuntime {
26	    /// Create an empty runtime with no actors or pending messages.
27	    /// `probe_name` names the embedded probe in its band-table
28	    /// report (e.g. `"goal1.dispatch"`).
29	    pub fn new(probe_name: &str) -> Self {
30	        Self {
31	            actors: Vec::new(),
32	            queue: VecDeque::new(),
33	            probe: TProbe2::new(probe_name),
34	        }
35	    }
36	
37	    /// Register `actor`; the returned `u32` is its stable id for
38	    /// the lifetime of the runtime and is usable as `dst_id` in
39	    /// [`Context::send`]. Ids are allocated sequentially from 0.
40	    pub fn add_actor(&mut self, actor: Box<dyn Actor>) -> u32 {
41	        let id = self.actors.len() as u32;
42	        self.actors.push(actor);
